                bestFromRight[i] = stMax.rangeMax(low, high);
            }
        }

        int[] dec_start = new int[n];
        dec_start[0] = 0;
        for (int i = 1; i < n; i++) {
            if (nums[i-1] > nums[i]) {
                dec_start[i] = dec_start[i-1];
            } else {
                dec_start[i] = i;
            }
        }

        SparseTableMin stForBestFromLeft = new SparseTableMin(bestFromLeft);
        long ans = Long.MIN_VALUE;

        for (int q = 2; q < n-1; q++) {
            if (bestFromRight[q] == Long.MIN_VALUE) {
                continue;
            }
            int L = dec_start[q];
            int R = q-1;
            if (L > R) {
                continue;
            }
            long minVal = stForBestFromLeft.rangeMin(L, R);
            if (minVal == Long.MAX_VALUE) {
                continue;
            }
            long candidate = bestFromRight[q] - minVal;
            if (candidate > ans) {
                ans = candidate;
            }
        }

        return ans;
    }
}
```

### Explanation
1. **Prefix Sum Calculation**: The prefix array is computed to store cumulative sums, allowing efficient range sum queries.
2. **Sparse Tables**: These tables are built for both range minimum and maximum queries on the prefix array, enabling efficient computation of the optimal segments for the three parts of the subarray.
3. **Increasing and Decreasing Runs**: For each position, we determine the start of the longest increasing run ending at that position and the start of the longest decreasing run ending at that position. This helps in identifying valid segments for the subarray parts.
4. **Best From Left and Right**: For each position, we compute the minimum prefix sum (for the left part) and the maximum prefix sum (for the right part) to maximize the subarray sum. This involves querying the sparse tables for the optimal values.
5. **Candidate Evaluation**: For each possible `q` (end of the decreasing part), we evaluate valid `p` values (start of the decreasing part) within the decreasing run ending at `q`. Using the precomputed values, we determine the maximum subarray sum that meets the problem's constraints by combining the optimal values from the left and right parts.

This approach efficiently narrows down the search space using precomputed runs and sparse tables, ensuring optimal performance even for large input sizes.
